class Solution {
    public int[] numsSameConsecDiff(int n, int k) {
        List<Integer> result = new ArrayList<>();
        for (int i = 1; i < Math.pow(10, n - 1); i++) {
            if (isValid(i, n, k)) {
                result.add(i);
            }
        }
        int[] res = new int[result.size()];
        for (int i = 0; i < result.size(); i++) {
            res[i] = result.get(i);
        }
        return res;
    }

    private boolean isValid(int num, int n, int k) {
        int count = 0;
        while (num > 0) {
            if (count == n - 1) {
                return true;
            }
            if (num % 10 - (num / 10) % 10 != k && num % 10 - (num / 10) % 10 != -k) {
                return false;
            }
            count++;
            num /= 10;
        }
        return true;
    }
}
